import { DynamoDBClient } from '@aws-sdk/client-dynamodb';
import { DynamoDBDocumentClient, PutCommand, GetCommand } from '@aws-sdk/lib-dynamodb';
import { NodeHttpHandler } from '@aws-sdk/node-http-handler';
import { ConfiguredRetryStrategy } from '@aws-sdk/util-retry';

// Configure exponential backoff with jitter for retry storm prevention
const retryStrategy = new ConfiguredRetryStrategy(
  10, // Max attempts (default: 3)
  (attempt) => {
    // Exponential backoff: 100ms * 2^attempt + random jitter
    const baseDelay = 100 * Math.pow(2, attempt);
    const jitter = Math.random() * 100; // Random 0-100ms jitter
    return Math.min(baseDelay + jitter, 20000); // Cap at 20 seconds
  }
);

const client = new DynamoDBClient({
  region: 'us-east-1',
  maxAttempts: 10,
  retryStrategy,
  requestHandler: new NodeHttpHandler({
    connectionTimeout: 5000,
    socketTimeout: 5000,
  }),
});

const docClient = DynamoDBDocumentClient.from(client, {
  marshallOptions: {
    removeUndefinedValues: true,
    convertClassInstanceToMap: true,
  },
});

// Write operation with throttle-aware error handling
async function writeItemSafely(tableName, item) {
  const params = {
    TableName: tableName,
    Item: item,
  };

  try {
    const result = await docClient.send(new PutCommand(params));
    console.log('Item written successfully');
    return result;
  } catch (error) {
    if (error.name === 'ProvisionedThroughputExceededException') {
      console.error('Throttling detected - Auto Scaling should kick in');
      // Emit CloudWatch metric for alerting
      throw new Error('DynamoDB throttled - backoff in progress');
    } else if (error.name === 'RequestLimitExceeded') {
      console.error('Account-level throttling - contact AWS Support');
      throw error;
    } else {
      throw error;
    }
  }
}

