// Circuit breaker pattern for cascade failure prevention
class DynamoDBCircuitBreaker {
  constructor(threshold = 5, timeout = 60000) {
    this.failureCount = 0;
    this.threshold = threshold;
    this.timeout = timeout;
    this.state = 'CLOSED'; // CLOSED, OPEN, HALF_OPEN
    this.nextAttempt = Date.now();
  }

  async execute(fn) {
    if (this.state === 'OPEN') {
      if (Date.now() < this.nextAttempt) {
        throw new Error('Circuit breaker is OPEN - rejecting request');
      }
      this.state = 'HALF_OPEN';
    }

    try {
      const result = await fn();
      this.onSuccess();
      return result;
    } catch (error) {
      this.onFailure();
      throw error;
    }
  }

  onSuccess() {
    this.failureCount = 0;
    this.state = 'CLOSED';
  }

  onFailure() {
    this.failureCount++;
    if (this.failureCount >= this.threshold) {
      this.state = 'OPEN';
      this.nextAttempt = Date.now() + this.timeout;
      console.error(`Circuit breaker OPENED after ${this.failureCount} failures`);
    }
  }
}

const circuitBreaker = new DynamoDBCircuitBreaker();

// Usage with circuit breaker
async function resilientWrite(tableName, item) {
  return circuitBreaker.execute(() => writeItemSafely(tableName, item));
}

// ANTI-PATTERN: Low-cardinality partition key (hot partition risk)
// ❌ BAD: Using date as partition key
const badSchema = {
  TableName: 'Orders',
  KeySchema: [
    { AttributeName: 'orderDate', KeyType: 'HASH' }, // Only ~365 unique values!
    { AttributeName: 'orderId', KeyType: 'RANGE' },
  ],
};
// All orders for today concentrate on ONE partition

// BEST PRACTICE: High-cardinality partition key with composite design
// ✅ GOOD: Using hashed userId or composite key
import crypto from 'crypto';

function generatePartitionKey(userId, shardCount = 100) {
  // Hash userId and distribute across N shards for even distribution
  const hash = crypto.createHash('md5').update(userId).digest('hex');
  const shard = parseInt(hash.substring(0, 8), 16) % shardCount;
  return `USER#${userId}#SHARD#${shard}`;
}

const goodSchema = {
  TableName: 'Orders',
  KeySchema: [
    { AttributeName: 'pk', KeyType: 'HASH' }, // High cardinality: userId + shard
    { AttributeName: 'sk', KeyType: 'RANGE' }, // orderDate#orderId for sorting
  ],
  AttributeDefinitions: [
    { AttributeName: 'pk', AttributeType: 'S' },
    { AttributeName: 'sk', AttributeType: 'S' },
    { AttributeName: 'gsi1pk', AttributeType: 'S' },
    { AttributeName: 'gsi1sk', AttributeType: 'S' },
  ],
  GlobalSecondaryIndexes: [
    {
      IndexName: 'GSI1',
      KeySchema: [
        { AttributeName: 'gsi1pk', KeyType: 'HASH' }, // e.g., "ORDER_STATUS#PENDING"
        { AttributeName: 'gsi1sk', KeyType: 'RANGE' }, // e.g., orderDate
      ],
      Projection: { ProjectionType: 'ALL' },
      ProvisionedThroughput: {
        ReadCapacityUnits: 100,
        WriteCapacityUnits: 100,
      },
    },
  ],
};

// Write operation with good partition key
async function createOrder(userId, orderData) {
  const orderId = crypto.randomUUID();
  const timestamp = new Date().toISOString();

  const item = {
    pk: generatePartitionKey(userId), // Evenly distributed
    sk: `ORDER#${timestamp}#${orderId}`,
    gsi1pk: `ORDER_STATUS#${orderData.status}`,
    gsi1sk: timestamp,
    userId,
    orderId,
    ...orderData,
  };

  await docClient.send(new PutCommand({
    TableName: 'Orders',
    Item: item,
  }));
}

