  Version: '2012-10-17',
  Statement: [
    {
      Sid: 'BlockScans',
      Effect: 'Deny',
      Principal: '*',
      Action: 'dynamodb:Scan',
      Resource: '*',
    },
    {
      Sid: 'AllowOtherOperations',
      Effect: 'Allow',
      Principal: '*',
      Action: 'dynamodb:*',
      Resource: '*',
    },
